from flask import Flask, request, make_response
import jwt
import json

app = Flask(__name__)

@app.route('/api/<path:path>', methods=['GET', 'POST'])
def proxy(path):
    token = request.headers.get('Authorization')
    
    if not token:
        return make_response("Missing Authorization Header", 401)
        
    try:
        decoded = jwt.decode(token, verify=False)
    except Exception as e:
        print(f"Error in decoding JWT: {e}")
        return make_response("Invalid token", 403)
    
    user_claims = json.dumps({'user': decoded['sub'], 'scope': decoded.get('scope', [])})
    
    resp = Flask.make_default_options_response(app)
    resp.headers['User-Claims'] = user_claims  # Forward the user claims to downstream services

    return resp

if __name__ == '__main__':
    app.run()